        it->second->freeze_first_col = (freeze != 0);
        it->second->freeze_col_count = (freeze != 0) ? 1 : 0;
        it->second->scroll_x = max(0, min(it->second->scroll_x, DataGrid_GetMaxScrollX(it->second)));
        InvalidateRect(hGrid, nullptr, TRUE);
