__declspec(dllexport) void __stdcall DataGrid_Enable(HWND hGrid, BOOL enable) {
    auto it = g_datagrids.find(hGrid);
    if (it == g_datagrids.end()) return;
    DataGridViewState* state = it->second;
    state->enabled = (enable != 0);

    // DataGridView 是完全自绘控件，交互是否可用已经由内部 enabled 状态控制。
    // 对外再调用 EnableWindow 会让 HWND 进入系统禁用态，恢复时偶发出现空白不重绘。
    // 这里保持窗口本身处于可绘制状态，只切换内部交互能力。
    if (!state->enabled && state->editing) {
        DataGrid_EndEdit(state, false);
    }

    InvalidateRect(hGrid, nullptr, TRUE);
}

__declspec(dllexport) void __stdcall DataGrid_Show(HWND hGrid, BOOL show) {
    ShowWindow(hGrid, show ? SW_SHOW : SW_HIDE);
}

__declspec(dllexport) void __stdcall DataGrid_SetBounds(HWND hGrid, int x, int y, int width, int height) {
    auto it = g_datagrids.find(hGrid);
    if (it == g_datagrids.end()) return;
    RECT px_rect = EW_LogicalChildRectToPx(GetParent(hGrid), x, y, width, height, true);
    it->second->x = px_rect.left; it->second->y = px_rect.top;
    it->second->width = EW_RectWidthPx(px_rect); it->second->height = EW_RectHeightPx(px_rect);
    EW_StoreLogicalBounds(hGrid, x, y, width, height, true);
    SetWindowPos(hGrid, NULL, px_rect.left, px_rect.top, it->second->width, it->second->height, SWP_NOZORDER);
}

__declspec(dllexport) void __stdcall DataGrid_Refresh(HWND hGrid) {
    InvalidateRect(hGrid, nullptr, TRUE);
}

__declspec(dllexport) void __stdcall DataGrid_SetColors(
    HWND hGrid,
    UINT32 fg_color,
    UINT32 bg_color,
    UINT32 header_bg_color,
    UINT32 header_fg_color,
    UINT32 select_color,
    UINT32 hover_color,
    UINT32 grid_line_color
) {
    auto it = g_datagrids.find(hGrid);
    if (it == g_datagrids.end()) return;

    DataGridViewState* state = it->second;
    state->fg_color = fg_color;
    state->bg_color = bg_color;
    state->header_bg_color = header_bg_color;
    state->header_fg_color = header_fg_color;
    state->select_color = select_color;
    state->hover_color = hover_color;
    state->grid_line_color = grid_line_color;
    state->zebra_color = (ColorLuma(bg_color) < 0.45f)
        ? LightenColor(bg_color, 1.12f)
        : 0xFFFAFAFA;

    // 主题色切换时要求立刻把选中色、悬停色和整表背景一起重绘出来，
    // 单纯 InvalidateRect 在某些宿主里会延迟到下一次消息循环后才完全刷新。
    RedrawWindow(hGrid, nullptr, nullptr, RDW_INVALIDATE | RDW_ERASE | RDW_UPDATENOW | RDW_FRAME);
}

__declspec(dllexport) int __stdcall DataGrid_GetColors(
    HWND hGrid,
    UINT32* fg_color,
    UINT32* bg_color,
    UINT32* header_bg_color,
    UINT32* header_fg_color,
    UINT32* select_color,
    UINT32* hover_color,
    UINT32* grid_line_color
) {
    auto it = g_datagrids.find(hGrid);
    if (it == g_datagrids.end()) return -1;

    DataGridViewState* state = it->second;
    if (fg_color) *fg_color = state->fg_color;
    if (bg_color) *bg_color = state->bg_color;
    if (header_bg_color) *header_bg_color = state->header_bg_color;
    if (header_fg_color) *header_fg_color = state->header_fg_color;
    if (select_color) *select_color = state->select_color;
    if (hover_color) *hover_color = state->hover_color;
    if (grid_line_color) *grid_line_color = state->grid_line_color;
    return 0;
}

// 设置列头对齐方式 (0=左对齐, 1=居中, 2=右对齐)
__declspec(dllexport) void __stdcall DataGrid_SetColumnHeaderAlignment(HWND hGrid, int col_index, int alignment) {
    auto it = g_datagrids.find(hGrid);
    if (it == g_datagrids.end()) return;
    DataGridViewState* state = it->second;
    if (col_index < 0 || col_index >= (int)state->columns.size()) return;
    
    DWRITE_TEXT_ALIGNMENT align = DWRITE_TEXT_ALIGNMENT_LEADING;
    if (alignment == 1) align = DWRITE_TEXT_ALIGNMENT_CENTER;
    else if (alignment == 2) align = DWRITE_TEXT_ALIGNMENT_TRAILING;
    
    state->columns[col_index].header_alignment = align;
    InvalidateRect(hGrid, nullptr, TRUE);
}

